import{c as n,S as c,j as o,m as h}from"./chunks/framework.8aa1YH_s.js";const g=JSON.parse('{"title":"Phân quyền","description":"","frontmatter":{},"headers":[],"relativePath":"admin/phan-quyen.md","filePath":"admin/phan-quyen.md","lastUpdated":0}'),d={name:"admin/phan-quyen.md"};function e(a,t,i,r,s,u){return c(),o("div",null,[...t[0]||(t[0]=[h('<h1 id="phan-quyen" tabindex="-1">Phân quyền <a class="header-anchor" href="#phan-quyen" aria-label="Permalink to “Phân quyền”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/account/permission</code></p><p>Phân quyền (Position / Permission) cho phép bạn tạo các <strong>chức vụ</strong> với từng quyền cụ thể, rồi gán cho nhân viên. Đây là cách an toàn nhất để chia sẻ quyền truy cập admin mà không &quot;trao chìa khóa&quot; toàn bộ.</p><h2 id="khai-niem" tabindex="-1">Khái niệm <a class="header-anchor" href="#khai-niem" aria-label="Permalink to “Khái niệm”">​</a></h2><ul><li><strong>Position (Chức vụ)</strong> = một nhóm quyền có tên, ví dụ: &quot;Quản trị cao cấp&quot;, &quot;Nhân viên CSKH&quot;.</li><li><strong>Permission (Quyền)</strong> = từng tính năng cụ thể, ví dụ: <code>student</code>, <code>course</code>, <code>exam</code>, <code>invoice</code>, …</li><li>Một <strong>nhân viên</strong> được gán đúng <strong>1 chức vụ</strong>, từ đó suy ra quyền.</li></ul><h2 id="danh-sach-quyen-co-san" tabindex="-1">Danh sách quyền có sẵn <a class="header-anchor" href="#danh-sach-quyen-co-san" aria-label="Permalink to “Danh sách quyền có sẵn”">​</a></h2><table tabindex="0"><thead><tr><th>Mã quyền</th><th>Cho phép truy cập</th></tr></thead><tbody><tr><td><code>student</code></td><td>Quản lý học viên</td></tr><tr><td><code>teacher</code></td><td>Quản lý giáo viên</td></tr><tr><td><code>staff</code></td><td>Quản lý nhân viên</td></tr><tr><td><code>position</code></td><td>Quản lý chức vụ / phân quyền</td></tr><tr><td><code>program</code></td><td>Khung chương trình</td></tr><tr><td><code>course</code></td><td>Khóa học</td></tr><tr><td><code>modun</code></td><td>Chương học (module)</td></tr><tr><td><code>thematic</code></td><td>Chuyên đề</td></tr><tr><td><code>lesson</code></td><td>Bài giảng</td></tr><tr><td><code>courseDescription</code></td><td>Thông tin khóa học (trang chi tiết, mô tả)</td></tr><tr><td><code>syntheticCriteria</code></td><td>Tiêu chí đề thi</td></tr><tr><td><code>exceprt</code></td><td>Trích đoạn đề thi</td></tr><tr><td><code>exam</code></td><td>Đề ôn / đề mẫu</td></tr><tr><td><code>examSet</code></td><td>Bộ đề thi</td></tr><tr><td><code>evaluate</code></td><td>Đánh giá đầu vào</td></tr><tr><td><code>question</code></td><td>Danh mục câu hỏi</td></tr><tr><td><code>courseStudent</code></td><td>Học viên - Khóa học</td></tr><tr><td><code>discountCode</code></td><td>Mã khuyến mãi</td></tr><tr><td><code>dealerDiscount</code></td><td>Chiết khấu / Đại lý</td></tr><tr><td><code>invoice</code></td><td>Hóa đơn</td></tr><tr><td><code>comment</code></td><td>Hỏi đáp</td></tr><tr><td><code>menu</code></td><td>Menu (banner)</td></tr><tr><td><code>footer</code></td><td>Footer hệ thống</td></tr><tr><td><code>contact</code></td><td>Liên hệ hệ thống</td></tr></tbody></table><blockquote><p>⚠️ Một số mục như <strong>Dashboard, Thống kê, Banner Quảng cáo, Ngân hàng</strong> hiện có thể mặc định bật cho mọi nhân viên - hãy test sau khi cấu hình.</p></blockquote><h2 id="tao-chuc-vu-moi" tabindex="-1">Tạo chức vụ mới <a class="header-anchor" href="#tao-chuc-vu-moi" aria-label="Permalink to “Tạo chức vụ mới”">​</a></h2><ol><li>Vào <code>https://lamsonedutech.vn/admin/account/permission</code> → bấm <strong>Thêm chức vụ</strong>.</li><li>Đặt <strong>Tên chức vụ</strong> (rõ ràng, ví dụ &quot;NV Kinh doanh khu vực Bắc&quot;).</li><li>(Tùy chọn) Mô tả ngắn.</li><li>Tick các <strong>quyền</strong> muốn bật.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="sua-chuc-vu" tabindex="-1">Sửa chức vụ <a class="header-anchor" href="#sua-chuc-vu" aria-label="Permalink to “Sửa chức vụ”">​</a></h2><ul><li>Bấm <strong>Sửa</strong> trên dòng → chỉnh quyền → <strong>Lưu</strong>.</li><li>Mọi nhân viên đang giữ chức vụ này <strong>sẽ áp dụng quyền mới ngay lần đăng nhập tiếp theo</strong>.</li></ul><h2 id="xoa-chuc-vu" tabindex="-1">Xóa chức vụ <a class="header-anchor" href="#xoa-chuc-vu" aria-label="Permalink to “Xóa chức vụ”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Chú ý</p><p>Không thể xóa chức vụ nếu vẫn còn nhân viên đang gán. Hãy chuyển những nhân viên đó sang chức vụ khác trước.</p></div><h2 id="ap-dung-cho-nhan-vien" tabindex="-1">Áp dụng cho nhân viên <a class="header-anchor" href="#ap-dung-cho-nhan-vien" aria-label="Permalink to “Áp dụng cho nhân viên”">​</a></h2><ol><li>Vào <a href="./quan-ly-nhan-vien">Quản lý Nhân viên</a>.</li><li>Bấm <strong>Sửa</strong> một nhân viên → mục <strong>Chức vụ</strong> → chọn chức vụ vừa tạo.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="meo-thuc-hanh" tabindex="-1">Mẹo thực hành <a class="header-anchor" href="#meo-thuc-hanh" aria-label="Permalink to “Mẹo thực hành”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Nguyên tắc tối thiểu quyền</p><p>Chỉ bật <strong>đúng những quyền cần thiết</strong> cho công việc. Ví dụ NV CSKH không cần quyền <code>course</code> hay <code>exam</code>.</p></div><div class="tip custom-block"><p class="custom-block-title">Tạo chức vụ &quot;Sandbox&quot;</p><p>Tạo một chức vụ &quot;Thử nghiệm&quot; để test giao diện trước khi tạo cho người thật. Có thể xóa sau khi đã chốt mẫu chức vụ.</p></div><div class="tip custom-block"><p class="custom-block-title">Xem audit trail</p><p>Nếu hệ thống có log thao tác, đối soát định kỳ ai đã sửa gì. Đặc biệt với quyền <code>invoice</code> và <code>student</code>.</p></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Nhân viên báo &quot;không vào được menu Khóa học&quot;.</strong> → Vào chức vụ của họ, bật quyền <code>course</code>. Yêu cầu họ đăng nhập lại.</p><p><strong>Tôi muốn cho 1 nhân viên CHỈ XEM mà không sửa được.</strong> → Hệ thống hiện chia quyền theo module chứ chưa có view-only chi tiết cho từng module. Có thể chờ giải pháp nâng cấp, hoặc thay bằng việc để nhân viên đó <strong>xem qua màn hình của người có quyền</strong>.</p><p><strong>Có cách nào tạo nhân viên Super Admin không?</strong> → Tạo chức vụ &quot;Super Admin&quot; → bật <strong>toàn bộ quyền</strong> → gán cho nhân viên đó. Tuy nhiên hạn chế số người ở mức này.</p>',24)])])}const m=n(d,[["render",e]]);export{g as __pageData,m as default};
